#include <iostream>

// Implement DynString: it owns a heap-allocated C-string and follows the
// Rule of Five (destructor, copy ctor, move ctor, copy assign, move assign).
// main below shows the interface it must expose.

DynString makeGreeting(const char* str); // build a DynString and return it

int main()
{
    char word[101]{};
    std::cin >> word;

    DynString a{ word };
    a.print();

    DynString b{ a };                  // copy
    b.print();

    DynString c{ makeGreeting(word) }; // move from the returned temporary
    c.print();

    DynString d{};
    d = DynString{};                   // move-assign an empty string
    d.print();

    return 0;
}

solution_code:
#include <iostream>

class DynString
{
    char* m_data{};
    int m_length{};

public:
    DynString() = default;

    DynString(const char* str)
    {
        m_length = 0;
        while (str[m_length] != '\0')
            ++m_length;
        m_data = new char[m_length + 1];
        for (int i{ 0 }; i <= m_length; ++i)
            m_data[i] = str[i];
    }

    ~DynString() { delete[] m_data; }

    DynString(const DynString& src)
        : m_length{ src.m_length }
    {
        if (src.m_data)
        {
            m_data = new char[m_length + 1];
            for (int i{ 0 }; i <= m_length; ++i)
                m_data[i] = src.m_data[i];
        }
    }

    DynString(DynString&& src) noexcept
        : m_data{ src.m_data }, m_length{ src.m_length }
    {
        src.m_data = nullptr;
        src.m_length = 0;
    }

    DynString& operator=(DynString&& src) noexcept
    {
        if (this != &src)
        {
            delete[] m_data;
            m_data = src.m_data;
            m_length = src.m_length;
            src.m_data = nullptr;
            src.m_length = 0;
        }
        return *this;
    }

    void print() const
    {
        std::cout << (m_data ? m_data : "empty") << '\n';
    }
};

DynString makeGreeting(const char* str)
{
    DynString ds{ str };
    return ds;
}

int main()
{
    char word[101]{};
    std::cin >> word;

    DynString a{ word };
    a.print();

    DynString b{ a };
    b.print();

    DynString c{ makeGreeting(word) };
    c.print();

    DynString d{};
    d = DynString{};
    d.print();

    return 0;
}

