#include <iostream>

// Implement MatrixRow: owns a heap-allocated double[] and follows the Rule of
// Five (deep-copy on copy, steal-and-null on move). main shows the interface.

MatrixRow makeFilledRow(int n, double value); // size-n row filled with value

int main()
{
    int n{};
    double val{};
    std::cin >> n >> val;

    MatrixRow a{ makeFilledRow(n, val) };
    a.print();

    MatrixRow b{ a };  // copy
    b.print();

    MatrixRow c{};
    c = makeFilledRow(n, val);  // move-assign
    c.print();
    std::cout << (c.size() == n ? "valid" : "invalid") << '\n';

    return 0;
}

